return {
  json: {
    user_prompt: $input.first().json.body ||
      $input.first().json || {
        prompt: "The user prompt is empty. Do not proceed. STOP!",
        context: "This is a broken user request - stop generation immediately!",
        documentType: "random",
        action: "analyze",
        summary: $input.first().json.body.summary,
      },

    createdAt: $now,
  },
};

const execution = $input.first().json;
const runData = execution.data.resultData.runData;

let logs = [];
let modelUsage = {};
let totalInputTokens = 0;
let totalOutputTokens = 0;

/**
 * Helper to safely extract node data
 */
const getNodesByType = (nodeName) => runData[nodeName] || [];

// 1. TRACK AI AGENTS & TOKEN USAGE
const aiNodeNames = ["Agent 1 - extract document structure", "Agent 1 - extract document structure1"];

aiNodeNames.forEach(nodeName => {
  const instances = getNodesByType(nodeName);
  instances.forEach(instance => {
    // n8n stores tokens in the metadata of the execution data
    const metadata = instance.metadata || {};
    const inputT = metadata.usage?.prompt_tokens || 0;
    const outputT = metadata.usage?.completion_tokens || 0;

    // Determine which model was likely used (from the node parameters or metadata)
    const model = instance.data?.main?.[0]?.[0]?.json?.model || "llama-3.1-8b"; 

    if (!modelUsage[model]) modelUsage[model] = { input: 0, output: 0, calls: 0 };
    modelUsage[model].input += inputT;
    modelUsage[model].output += outputT;
    modelUsage[model].calls += 1;

    totalInputTokens += inputT;
    totalOutputTokens += outputT;

    logs.push({
      type: "AI_GENERATION",
      node: nodeName,
      model: model,
      tokens: { input: inputT, output: outputT },
      duration: instance.executionTime,
      timestamp: new Date(instance.startTime).toISOString()
    });
  });
});

// 2. TRACK GOOGLE SHEETS READS
const sheetNodes = ["Get row(s) in sheet", "Get row(s) in sheet1"];
sheetNodes.forEach(nodeName => {
  const instances = getNodesByType(nodeName);
  instances.forEach(instance => {
    const rowsFound = instance.data?.main?.[0]?.length || 0;
    const firstRow = instance.data?.main?.[0]?.[0]?.json || {};

    logs.push({
      type: "GOOGLE_SHEETS_READ",
      node: nodeName,
      details: {
        documentTypeFound: firstRow.document_type || "unknown",
        rowsExtracted: rowsFound
      },
      duration: instance.executionTime,
      timestamp: new Date(instance.startTime).toISOString()
    });
  });
});

// 3. TRACK EXTERNAL HTTP API REQUESTS
const httpInstances = getNodesByType("HTTP Request");
httpInstances.forEach(instance => {
  logs.push({
    type: "EXTERNAL_API_CALL",
    node: "HTTP Request",
    url: "https://bpma-afs-tools.automation-for-smes.com/api/v1/executions",
    method: "GET",
    status: instance.executionStatus,
    resultsCount: instance.data?.main?.[0]?.[0]?.json?.data?.length || 0,
    duration: instance.executionTime
  });
});

// 4. CONSTRUCT FINAL ANALYTICS OBJECT
const summary = {
  executionId: execution.id,
  user: runData["Webhook"]?.[0]?.data?.main?.[0]?.[0]?.json?.body?.userId || "anonymous",
  summaryUsage: {
    totalInputTokens,
    totalOutputTokens,
    totalCalls: logs.length,
    modelBreakdown: modelUsage
  },
  allOperations: logs
};

// 5. GENERATE MESSAGES
const adminMsg = `📊 Usage Report [Exec: ${execution.id}]\n` +
                 `- Tokens: ${totalInputTokens} in / ${totalOutputTokens} out\n` +
                 `- Models: ${Object.keys(modelUsage).join(', ')}\n` +
                 `- Operations: ${logs.length} API interactions.`;

return {
  analytics: summary,
  adminNotification: adminMsg,
  rawLogs: logs
};

const results = {
  agentResults: $('parse agent 2 output').first().json,
  driveResults: $('Upload file').first().json
}
return results;

