// 1️⃣ Grab the raw row data
const raw = $input.first().json;          // e.g. the object shown above

// 2️⃣ Helper: simple {{…}} replacement using the current item
function renderTemplate(template, data) {
  return template.replace(/\{\{([^}]+)\}\}/g, (_, key) => {
    const parts = key.trim().split('.');   // e.g. "user_prompt.theme"
    let value = data;
    for (const part of parts) {
      if (value && part in value) {
        value = value[part];
      } else {
        // If the key is missing, leave the placeholder unchanged
        return `{{${key}}}`;
      }
    }
    // If the value is an object, stringify it
    return typeof value === 'object' ? JSON.stringify(value) : String(value);
  });
}

// 3️⃣ Build the new object
const output = {};

for (const [key, value] of Object.entries(raw)) {
  // If the key matches an agent column, render it
  if (/^agent_\d+_(user|system)$/.test(key) && typeof value === 'string') {
    output[key] = renderTemplate(value, raw);   // you can pass any data you need
  } else {
    // keep all other columns untouched
    output[key] = value;
  }
}

// 4️⃣ Return the updated item (n8n expects an array of items)
return [output];

// Get the raw output from the previous node
// Replace 'output' with the actual field name from your AI node (e.g., 'text' or 'message.content')
const rawContent = 
$("Agent 3: HTML Designer").first().json.output;
 try {
  // 1. Use Regex to find the first '{' and the last '}'
  // This ignores <think> tags and any "Here is your JSON:" preamble
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    // 2. Parse the extracted string into a real JSON object
    const cleanJson = JSON.parse(jsonMatch[0]);

    // 3. Return the parsed object to the workflow
    return [{ json: cleanJson }];
  } else {
    throw new Error("No JSON object found in the output.");
  }
} catch (error) {
  // If parsing fails, return the error and the raw text for debugging
  return [{ 
    json: { 
      error: "Failed to parse JSON", 
      message: error.message,
      raw: rawContent 
    } 
  }];
}

// Get the raw string from the 'output' field
const rawString = $input.first().json.output;
try {
return {json: JSON.parse(rawString)};

} catch (error) {
const clean = {
  data: rawString
    .replaceAll("\n", "")
    .replaceAll('\\"', '"')
    // .replaceAll('"', '')
    .replaceAll(/\r/g, "")
    .replaceAll(/\n/g, "")
    .replaceAll(/\u00A0/g, " "),
};
return {json: JSON.parse(clean.data)};
}

